<figure className="my-4 mx-auto text-center bg-white rounded-[10px] p-[14px] border border-line max-w-[680px]"><img src="data:image/png;base64," alt="Wykres oczkowy"/><figcaption className="font-mono text-[11px] text-[#555] mt-2 text-left">Rysunek 5.4. Wykres oczkowy.</figcaption></figure>
